import{_ as t,o,c as i,a2 as a}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Hero Section","description":"Sikika Theme Hero Section","frontmatter":{"title":"Hero Section","description":"Sikika Theme Hero Section","weight":30,"extra":{"order":30},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/sikika/hero-section"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/sikika/hero-section"}],["meta",{"property":"og:title","content":"Hero Section"}],["meta",{"property":"og:description","content":"Sikika Theme Hero Section"}],["meta",{"name":"twitter:title","content":"Hero Section"}],["meta",{"name":"twitter:description","content":"Sikika Theme Hero Section"}]]},"headers":[],"relativePath":"docs/sikika/hero-section.md","filePath":"docs/sikika/hero-section.md"}'),n={name:"docs/sikika/hero-section.md"};function r(l,e,s,c,h,d){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="hero-section" tabindex="-1">Hero Section <a class="header-anchor" href="#hero-section" aria-label="Permalink to &quot;Hero Section&quot;">​</a></h1><p>Sikika includes a customizable hero section for your pages. The hero section appears at the top of your pages and can be configured with various elements.</p><hr><h3 id="hero-section-options" tabindex="-1">Hero Section Options <a class="header-anchor" href="#hero-section-options" aria-label="Permalink to &quot;Hero Section Options&quot;">​</a></h3><p>When editing a page, you&#39;ll find a &quot;Hero Section&quot; meta box with the following options:</p><h4 id="text-elements" tabindex="-1">Text Elements <a class="header-anchor" href="#text-elements" aria-label="Permalink to &quot;Text Elements&quot;">​</a></h4><ul><li><strong>Hero Pre Text</strong>: Small text that appears above the main title</li><li><strong>Hero Highlight Text</strong>: Parts of the title to highlight in a different color</li><li><strong>Hero Text</strong>: Main description text that appears below the title</li><li><strong>Display Meta</strong>: Toggle to show/hide author and date below the heading</li></ul><h4 id="visual-elements" tabindex="-1">Visual Elements <a class="header-anchor" href="#visual-elements" aria-label="Permalink to &quot;Visual Elements&quot;">​</a></h4><ul><li><strong>Hero Image</strong>: Background image for the hero section</li><li><strong>Hero SVG</strong>: Alternative to hero image, allows custom SVG graphics <blockquote><p><strong>Note:</strong> The Hero Image and Hero SVG fields are mutually exclusive. If you use an SVG, the image field should be empty.</p></blockquote></li></ul><h4 id="call-to-action" tabindex="-1">Call to Action <a class="header-anchor" href="#call-to-action" aria-label="Permalink to &quot;Call to Action&quot;">​</a></h4><ul><li><strong>Button URL</strong>: Link for the call-to-action button</li><li><strong>Button Label</strong>: Text for the call-to-action button</li></ul><h3 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h3><ol><li>Edit any page</li><li>Scroll down to find the &quot;Hero Section&quot; meta box</li><li>Configure the desired elements: <ul><li>Add pre-text and highlight text for emphasis</li><li>Write a compelling hero text</li><li>Choose between a background image or custom SVG</li><li>Add a call-to-action button if needed</li></ul></li><li>Update or publish the page</li></ol>',13)])])}const p=t(n,[["render",r]]);export{m as __pageData,p as default};
